org.redisson.api.RLock.scenario_case:
// 典型用法：防止超卖
RLock lock = redissonClient.getLock("product_stock_101");
try {
    if (lock.tryLock(10, TimeUnit.SECONDS)) {
        // 执行业务逻辑
    }
} finally {
    lock.unlock();
}

